// Generate comprehensive customer care dataset with 500 records
const categories = ['order_tracking', 'delivery_delay', 'refund_request', 'product_complaint', 'subscription_issue', 'payment_failure', 'general_question'];
const sentiments = ['positive', 'neutral', 'negative', 'critical'];
const urgencies = ['low', 'medium', 'high', 'critical'];
const products = ['Whey Protein', 'Whey Isolate', 'Creatine', 'Mass Gainer', 'Pre-Workout', 'BCAA', 'Multivitamin'];
const resolutionPaths = ['A', 'B', 'C'];

const queries = {
  order_tracking: [
    'Where is my order BL-{id}?',
    'Can you track my order {id}?',
    'Order status for BL-{id}',
    'When will order {id} arrive?'
  ],
  delivery_delay: [
    'My order BL-{id} is delayed',
    'Order {id} not received yet',
    'Delivery is very late for BL-{id}',
    'Still waiting for order {id}'
  ],
  refund_request: [
    'I want refund for order BL-{id}',
    'Please refund my payment for {id}',
    'Cancel order {id} and refund',
    'Refund request for BL-{id}'
  ],
  product_complaint: [
    'Product {product} is damaged',
    '{product} quality is poor',
    'Received wrong product instead of {product}',
    '{product} expired on arrival'
  ],
  subscription_issue: [
    'Cancel my subscription',
    'Change subscription delivery date',
    'Pause my monthly subscription',
    'Update subscription address'
  ],
  payment_failure: [
    'Payment failed for order BL-{id}',
    'Transaction {payment} not processed',
    'Money deducted but order not placed',
    'Payment error for {id}'
  ],
  general_question: [
    'What is {product}?',
    'How to use {product}?',
    'Is {product} safe?',
    'Difference between Whey and Isolate?'
  ]
};

const responses = {
  A: [
    'Your order is currently in transit and will arrive soon.',
    'We are sorry for the delay. Your order is on the way.',
    'Your refund request has been initiated successfully.',
    'Payment issue resolved. Please try again.',
    'Your subscription has been updated as requested.'
  ],
  B: [
    'Whey Protein contains 24g protein per serving with lactose.',
    'Whey Isolate is low lactose, suitable for sensitive users.',
    'Creatine is safe at 3-5g daily dosage.',
    'Mass Gainer provides high calories for weight gain.',
    'Pre-Workout boosts energy and focus during training.'
  ],
  C: [
    'Hi, I understand this is important. I have escalated your issue to our support team. They will contact you shortly.',
    'Your case has been escalated to senior support. Expect a call within 24 hours.',
    'This requires human attention. Our team will reach out soon.'
  ]
};

const dataset = [];

for (let i = 1; i <= 500; i++) {
  const category = categories[Math.floor(Math.random() * categories.length)];
  const sentiment = sentiments[Math.floor(Math.random() * sentiments.length)];
  const urgency = urgencies[Math.floor(Math.random() * urgencies.length)];
  const product = products[Math.floor(Math.random() * products.length)];
  const path = resolutionPaths[Math.floor(Math.random() * resolutionPaths.length)];

  const queryTemplates = queries[category];
  let query = queryTemplates[Math.floor(Math.random() * queryTemplates.length)];
  query = query.replace('{id}', 10000 + i);
  query = query.replace('{product}', product);
  query = query.replace('{payment}', 'pay_' + Math.random().toString(36).substr(2, 9));

  const confidence = Math.random() * 0.5 + 0.5; // 0.5 to 1.0
  const requires_human = sentiment === 'critical' || confidence < 0.6;

  const responseList = responses[path];
  const response = responseList[Math.floor(Math.random() * responseList.length)];

  dataset.push({
    id: i,
    timestamp: new Date(Date.now() - Math.random() * 30 * 24 * 60 * 60 * 1000).toISOString(),
    customer_query: query,
    category: category,
    sentiment: sentiment,
    urgency: urgency,
    confidence: parseFloat(confidence.toFixed(2)),
    requires_human: requires_human,
    order_id: category.includes('order') || category.includes('delivery') || category.includes('refund') ? 'BL-' + (10000 + i) : null,
    payment_id: category === 'payment_failure' ? 'pay_' + Math.random().toString(36).substr(2, 9) : null,
    product_name: category === 'product_complaint' || category === 'general_question' ? product : null,
    amount: category === 'refund_request' || category === 'payment_failure' ? Math.floor(Math.random() * 5000) + 500 : null,
    resolution_path: path,
    bot_response: response,
    resolution_time_seconds: Math.floor(Math.random() * 300) + 10,
    customer_satisfied: Math.random() > 0.3,
    escalated_to_human: requires_human
  });
}

return dataset.map(item => ({ json: item }));

// Group interactions by week and category
const items = $input.all().map(i => i.json);

// Helper to get week number
function getWeekNumber(date) {
  const d = new Date(date);
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + 4 - (d.getDay() || 7));
  const yearStart = new Date(d.getFullYear(), 0, 1);
  const weekNo = Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
  return `${d.getFullYear()}-W${weekNo.toString().padStart(2, '0')}`;
}

const weeklyData = {};

items.forEach(item => {
  const week = getWeekNumber(item.timestamp);
  const category = item.category;

  if (!weeklyData[week]) {
    weeklyData[week] = {};
  }

  if (!weeklyData[week][category]) {
    weeklyData[week][category] = 0;
  }

  weeklyData[week][category]++;
});

// Convert to array format
const result = [];
for (const week in weeklyData) {
  for (const category in weeklyData[week]) {
    result.push({
      week: week,
      category: category,
      count: weeklyData[week][category]
    });
  }
}

// Sort by week and category
result.sort((a, b) => {
  if (a.week !== b.week) return a.week.localeCompare(b.week);
  return a.category.localeCompare(b.category);
});

return result.map(item => ({ json: item }));

// Process all analytics data into dashboard structure
const allData = $input.all().map(i => i.json);

// Separate data by type
const categoryData = allData.filter(d => d.category && d.id_count);
const totalData = allData.find(d => d.id_count && !d.category && !d.sentiment && !d.resolution_path);
const sentimentData = allData.filter(d => d.sentiment && d.id_count);
const resolutionData = allData.filter(d => d.resolution_path && d.id_count);
const weeklyData = allData.filter(d => d.week && d.category && d.count);

const totalCount = totalData ? totalData.id_count : 500;

// Calculate percentages for category distribution
const categoryDistribution = categoryData.map(item => ({
  category: item.category,
  count: item.id_count,
  percentage: ((item.id_count / totalCount) * 100).toFixed(1)
})).sort((a, b) => b.count - a.count);

// Calculate sentiment breakdown
const sentimentBreakdown = sentimentData.map(item => ({
  sentiment: item.sentiment,
  count: item.id_count,
  percentage: ((item.id_count / totalCount) * 100).toFixed(1)
}));

// Calculate resolution path metrics
const resolutionMetrics = resolutionData.map(item => ({
  path: item.resolution_path,
  path_name: item.resolution_path === 'A' ? 'Auto Resolution' : item.resolution_path === 'B' ? 'Knowledge Base' : 'Human Escalation',
  count: item.id_count,
  percentage: ((item.id_count / totalCount) * 100).toFixed(1),
  avg_confidence: item.confidence_average ? item.confidence_average.toFixed(2) : 'N/A',
  avg_resolution_time: item.resolution_time_seconds_average ? Math.round(item.resolution_time_seconds_average) : 'N/A'
}));

// Group weekly trends by week
const weeklyTrends = {};
weeklyData.forEach(item => {
  if (!weeklyTrends[item.week]) {
    weeklyTrends[item.week] = { week: item.week, categories: {} };
  }
  weeklyTrends[item.week].categories[item.category] = item.count;
});

const weeklyTrendsArray = Object.values(weeklyTrends);

// Calculate automation opportunities
const autoResolved = resolutionData.find(d => d.resolution_path === 'A');
const knowledgeBase = resolutionData.find(d => d.resolution_path === 'B');
const humanEscalation = resolutionData.find(d => d.resolution_path === 'C');

const automationRate = autoResolved && knowledgeBase ? 
  (((autoResolved.id_count + knowledgeBase.id_count) / totalCount) * 100).toFixed(1) : '0';

const dashboard = {
  metadata: {
    title: 'BeastBot Customer Care Analytics Dashboard',
    generated_at: new Date().toISOString(),
    total_interactions: totalCount,
    date_range: 'Last 30 days'
  },
  problem_distribution: {
    title: 'Problem Distribution',
    categories: categoryDistribution
  },
  sentiment_analysis: {
    title: 'Customer Sentiment Breakdown',
    sentiments: sentimentBreakdown
  },
  resolution_performance: {
    title: 'Resolution Path Performance',
    paths: resolutionMetrics
  },
  weekly_trends: {
    title: 'Weekly Trends',
    data: weeklyTrendsArray
  },
  automation_insights: {
    title: 'Automation Opportunities',
    automation_rate: automationRate + '%',
    auto_resolved_count: autoResolved ? autoResolved.id_count : 0,
    knowledge_base_count: knowledgeBase ? knowledgeBase.id_count : 0,
    human_escalation_count: humanEscalation ? humanEscalation.id_count : 0,
    recommendations: [
      {
        area: 'Order Tracking',
        current_automation: 'High',
        opportunity: 'Implement proactive order status notifications to reduce incoming queries by 30%',
        impact: 'High'
      },
      {
        area: 'Delivery Delays',
        current_automation: 'Medium',
        opportunity: 'Auto-detect delays and send preemptive updates with compensation offers',
        impact: 'High'
      },
      {
        area: 'Product Questions',
        current_automation: 'High',
        opportunity: 'Expand knowledge base with video tutorials and comparison charts',
        impact: 'Medium'
      },
      {
        area: 'Refund Requests',
        current_automation: 'Low',
        opportunity: 'Enable AI to auto-approve refunds under ₹500 based on order history',
        impact: 'High'
      }
    ]
  },
  tools_and_workflow: {
    ai_tools: [
      'Groq (llama3-8b-8192) - Fast LLM inference for real-time classification',
      'Structured Output Parser - Ensures consistent JSON responses',
      'LangChain Agent - Orchestrates AI decision-making pipeline'
    ],
    automation_platform: 'n8n - Open-source workflow automation',
    data_storage: 'n8n Data Tables - Persistent storage for interaction logs',
    architecture: [
      '1. Chat Trigger → Receives customer query',
      '2. AI Classifier → Analyzes query, extracts entities, determines sentiment',
      '3. Switch Router → Routes to Auto/Knowledge/Escalation path',
      '4. Data Logger → Stores all interactions for analytics',
      '5. Response Handler → Sends appropriate reply to customer',
      '6. Analytics Engine → Aggregates data for dashboard insights'
    ],
    scalability: {
      current_capacity: '500-1000 queries/day',
      scaling_strategy: [
        'Batch processing for high-volume periods',
        'Caching common responses to reduce AI calls',
        'Load balancing across multiple workflow instances',
        'Database indexing on category and timestamp fields'
      ]
    }
  }
};

return [{ json: dashboard }];

// Merge multiple intent responses into one coherent message
const responses = $input.all().map(i => i.json);

if (responses.length === 1) {
  return [{ json: responses[0] }];
}

const finalResponse = responses.map((r, idx) => 
  `${idx + 1}. ${r.output?.response ?? r.finalResponse ?? "Processed"}`
).join("\n\n");

const categories = responses.map(r => r.output?.category ?? r.category).filter(Boolean);

return [{
  json: {
    finalResponse: `I've addressed multiple concerns:\n\n${finalResponse}`,
    categories: categories,
    multi_intent: true
  }
}];

// Detect spikes in category counts
const items = $input.all().map(i => i.json);
const categoryData = items.filter(d => d.category && d.id_count);

const alerts = [];
const THRESHOLD = 50; // Alert if category > 50 queries

categoryData.forEach(cat => {
  if (cat.id_count > THRESHOLD) {
    alerts.push({
      alert_type: "spike_detected",
      category: cat.category,
      count: cat.id_count,
      threshold: THRESHOLD,
      severity: cat.id_count > 100 ? "critical" : "warning",
      message: `⚠️ Spike detected: ${cat.category} has ${cat.id_count} queries (threshold: ${THRESHOLD})`
    });
  }
});

return alerts.length > 0 ? alerts.map(a => ({ json: a })) : [{ json: { alert_type: "no_spike", message: "All categories within normal range" } }];
